head.b:skin:
/*------------------------------------------------------------
GLOBAL BRAND CORE VARIABLE ARCHITECTURE
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff1e56 0%, #ffac41 50%, #3232ff 100%);
    --secondary-gradient: linear-gradient(90deg, #1e3a8a 0%, #3b82f6 100%);
    --neon-glow: 0 0 30px rgba(255, 30, 86, 0.35);
    --dark-bg: #030712;
    --dark-card: #0f172a;
    --light-bg: #f8fafc;
    --light-card: #ffffff;
    --text-main: #0f172a;
    --text-muted: #475569;
    --accent-color: #ff1e56;
    --border-color: rgba(0, 0, 0, 0.06);
    --font-global: 'Plus Jakarta Sans', 'Noto Sans Devanagari', sans-serif;
    --radius-mega: 20px;
    --radius-sm: 10px;
    --shadow-mega: 0 25px 60px -15px rgba(15, 23, 42, 0.06);
    --transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f1f5f9;
    --text-muted: #94a3b8;
    --border-color: rgba(255, 255, 255, 0.08);
    --shadow-mega: 0 30px 70px rgba(0, 0, 0, 0.55);
}

/* Core Layout Foundations */
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font-global); background-color: var(--light-bg); color: var(--text-main); transition: var(--transition); overflow-x: hidden; -webkit-font-smoothing: antialiased; }
a { color: inherit; text-decoration: none; transition: var(--transition); }
img { max-width: 100%; height: auto; display: block; border-radius: 12px; }
ul { list-style: none; }

#progress-bar { position: fixed; top: 0; left: 0; width: 0%; height: 5px; background: var(--primary-gradient); z-index: 100000; }
.container { max-width: 1400px; margin: 0 auto; padding: 0 24px; }

/* Top Bar Live Ticker Style Framework */
.top-bar { background: #090d16; color: #fff; padding: 14px 0; font-size: 13.5px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.ticker-wrap { display: flex; align-items: center; justify-content: space-between; gap: 20px; }
.ticker-box { display: flex; align-items: center; overflow: hidden; width: 80%; }
.ticker-title { background: var(--primary-gradient); padding: 7px 18px; font-weight: 900; border-radius: 8px; margin-right: 20px; white-space: nowrap; font-size: 12px; box-shadow: var(--neon-glow); animation: pulse 2s infinite; text-transform: uppercase; }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker-live 35s linear infinite; color: #e2e8f0; font-weight: 700; }
@keyframes ticker-live { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/* Ultra Luxury Responsive Sticky Navbar */
header { background: rgba(255, 255, 255, 0.85); backdrop-filter: blur(30px); -webkit-backdrop-filter: blur(30px); position: sticky; top: 0; z-index: 9999; box-shadow: 0 4px 30px rgba(0,0,0,0.02); border-bottom: 1px solid var(--border-color); padding: 18px 0; }
body.dark-mode header { background: rgba(15, 23, 42, 0.85); }
.header-inner { display: flex; flex-direction: column; align-items: center; gap: 24px; }
@media(min-width: 992px) { .header-inner { flex-direction: row; justify-content: space-between; } }

.logo-branding { position: relative; padding: 8px 30px; text-align: center; background: rgba(255, 30, 86, 0.02); border-radius: 16px; border: 1px solid rgba(255, 30, 86, 0.08); }
.logo-branding h1 { font-size: 48px; font-weight: 900; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; letter-spacing: -2px; text-transform: uppercase; line-height: 1.1; filter: drop-shadow(0 2px 12px rgba(255,30,86,0.2)); }
.logo-sub { display: block; font-size: 11px; font-weight: 900; color: var(--text-muted); letter-spacing: 7px; text-transform: uppercase; margin-top: 6px; }

nav ul { display: flex; gap: 28px; flex-wrap: wrap; justify-content: center; }
nav ul li a { font-weight: 800; font-size: 15.5px; color: var(--text-main); padding: 10px 0; position: relative; display: flex; align-items: center; gap: 8px; }
nav ul li a::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 4px; background: var(--primary-gradient); transition: var(--transition); border-radius: 4px; }
nav ul li a:hover::after { width: 100%; }

.nav-actions { display: flex; align-items: center; gap: 15px; }
.mode-btn { width: 48px; height: 48px; border-radius: 14px; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; border: 1px solid var(--border-color); transition: var(--transition); color: var(--text-main); }
.mode-btn:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-3px) rotate(15deg); box-shadow: var(--neon-glow); }

/* Super Featured Mega Grid Showcase Block */
.featured-hero-grid { display: grid; grid-template-columns: 1fr; gap: 24px; margin-top: 40px; }
@media(min-width: 992px) { .featured-hero-grid { grid-template-columns: 2fr 1fr; } }
.hero-banner-main { position: relative; height: 460px; border-radius: var(--radius-mega); overflow: hidden; box-shadow: var(--shadow-mega); }
.hero-banner-main img { width: 100%; height: 100%; object-fit: cover; }
.hero-overlay { position: absolute; inset: 0; background: linear-gradient(to top, rgba(3,7,18,0.98) 0%, rgba(3,7,18,0.4) 65%, transparent 100%); display: flex; flex-direction: column; justify-content: flex-end; padding: 45px; }
.hero-title { color: #fff; font-size: 32px; font-weight: 900; line-height: 1.35; margin-top: 12px; }

.hero-side-flex { display: flex; flex-direction: column; gap: 20px; }
.hero-side-card { background: var(--primary-gradient); padding: 35px; border-radius: var(--radius-mega); color: #fff; box-shadow: var(--neon-glow); height: 100%; display: flex; flex-direction: column; justify-content: center; position: relative; overflow: hidden; }
.hero-side-card::before { content: '\f5da'; font-family: 'Font Awesome 6 Free'; font-weight: 900; position: absolute; bottom: -20px; right: -10px; font-size: 140px; opacity: 0.08; }

/* Layout Structural Split Engine Grid */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 50px; margin-top: 50px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.5fr 1fr; } }

/* Premium Content Grid Card Elements */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 40px; }
@media(min-width: 680px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: var(--radius-mega); overflow: hidden; box-shadow: var(--shadow-mega); border: 1px solid var(--border-color); display: flex; flex-direction: column; height: 100%; transition: var(--transition); }
.card:hover { transform: translateY(-12px); box-shadow: 0 40px 80px rgba(255, 30, 86, 0.16); border-color: rgba(255, 30, 86, 0.3); }
.card-thumb { height: 260px; background: #0f172a; position: relative; overflow: hidden; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: var(--transition); }
.card:hover .card-thumb img { transform: scale(1.08); }

.badge { position: absolute; top: 20px; left: 20px; background: var(--primary-gradient); color: #fff; padding: 6px 18px; font-size: 11.5px; font-weight: 900; border-radius: 8px; box-shadow: var(--neon-glow); text-transform: uppercase; letter-spacing: 0.5px; }
.card-content { padding: 30px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 13.5px; color: var(--text-muted); margin-bottom: 15px; display: flex; gap: 18px; font-weight: 700; }
.card-meta i { color: var(--accent-color); }
.card-title { font-size: 23px; font-weight: 800; line-height: 1.45; margin-bottom: 15px; color: var(--text-main); transition: var(--transition); }
.card-title a:hover { color: var(--accent-color); }
.card-text { font-size: 15px; color: var(--text-muted); line-height: 1.75; margin-bottom: 26px; }
.read-btn { font-weight: 800; font-size: 15px; color: var(--accent-color); display: inline-flex; align-items: center; gap: 8px; }

/* Single Page View Presentation Layer Typography */
.post-body-container { background: var(--light-card); padding: 50px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid var(--border-color); }
.post-main-title { font-size: 42px; font-weight: 900; line-height: 1.35; margin-bottom: 26px; color: var(--text-main); letter-spacing: -0.8px; }
.breadcrumb-nav { display: flex; gap: 8px; font-size: 14.5px; color: var(--text-muted); margin-bottom: 30px; font-weight: 700; }
.post-content-inner { font-size: 18px; line-height: 2; color: var(--text-main); }
.post-content-inner p { margin-bottom: 26px; }
.post-content-inner h2, .post-content-inner h3 { font-size: 30px; font-weight: 800; margin: 45px 0 22px; border-left: 6px solid var(--accent-color); padding-left: 20px; background: linear-gradient(90deg, rgba(255,30,86,0.04), transparent); padding-vertical: 8px; color: var(--text-main); }

/* Social Share Panel Block */
.share-container { display: flex; gap: 15px; margin: 45px 0; flex-wrap: wrap; }
.share-btn { padding: 15px 26px; border-radius: 12px; color: #fff; font-size: 15px; font-weight: 800; display: flex; align-items: center; gap: 12px; box-shadow: 0 6px 22px rgba(0,0,0,0.06); cursor: pointer; }
.share-fb { background: #1877f2; }
.share-wa { background: #25d366; }
.share-tw { background: #1da1f2; }

/* Premium Video Multi-Layout Highlight Section */
.video-gallery-panel { margin-top: 55px; background: #0b1329; border-radius: var(--radius-mega); padding: 40px; color: #fff; }
.video-title-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 30px; }
.video-title-header h3 { font-size: 24px; font-weight: 900; letter-spacing: -0.5px; }
.video-grid-system { display: grid; grid-template-columns: 1fr; gap: 24px; }
@media(min-width: 768px) { .video-grid-system { grid-template-columns: repeat(3, 1fr); } }
.video-item-box { background: rgba(255,255,255,0.03); border-radius: 16px; overflow: hidden; border: 1px solid rgba(255,255,255,0.05); transition: var(--transition); }
.video-item-box:hover { transform: scale(1.04); background: rgba(255,255,255,0.06); }
.video-thumb-wrap { position: relative; height: 170px; background: #000; }
.video-thumb-wrap img { width: 100%; height: 100%; object-fit: cover; opacity: 0.8; }
.play-icon-center { position: absolute; inset: 0; margin: auto; width: 50px; height: 50px; background: var(--accent-color); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 18px; box-shadow: var(--neon-glow); }
.video-info-box { padding: 20px; }
.video-info-box h4 { font-size: 15.5px; font-weight: 800; line-height: 1.4; margin-bottom: 8px; }

/* Infinite Hot Trend Now Highlight Block Grid */
.hot-trend-box { margin-top: 55px; background: var(--light-card); border-radius: var(--radius-mega); padding: 40px; box-shadow: var(--shadow-mega); border: 1px solid var(--border-color); position: relative; }
.hot-trend-box::before { content: ''; position: absolute; top: 0; left: 0; width: 6px; height: 100%; background: var(--primary-gradient); border-radius: 20px 0 0 20px; }
.trend-head { display: flex; align-items: center; gap: 15px; margin-bottom: 30px; }
.trend-head h3 { font-size: 22px; font-weight: 900; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; text-transform: uppercase; }
.trend-icon-flash { background: var(--primary-gradient); color: #fff; width: 40px; height: 40px; border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 18px; box-shadow: var(--neon-glow); }

.trend-grid { display: grid; grid-template-columns: 1fr; gap: 26px; }
@media(min-width: 600px) { .trend-grid { grid-template-columns: 1fr 1fr; } }
.trend-item { display: flex; gap: 20px; align-items: center; background: var(--light-bg); padding: 20px; border-radius: 16px; border: 1px solid var(--border-color); transition: var(--transition); }
.trend-item:hover { transform: scale(1.03); background: var(--light-card); box-shadow: 0 20px 45px rgba(0,0,0,0.05); border-color: rgba(255, 30, 86, 0.25); }
.trend-img-holder { width: 90px; height: 90px; border-radius: 12px; overflow: hidden; flex-shrink: 0; }
.trend-img-holder img { width: 100%; height: 100%; object-fit: cover; }
.trend-info h4 { font-size: 15.5px; font-weight: 800; line-height: 1.45; color: var(--text-main); margin-bottom: 6px; }
.trend-meta { font-size: 13px; color: var(--text-muted); font-weight: 700; }

/* Ultra Advanced Sidebar Block Architecture */
.sidebar-pane { display: flex; flex-direction: column; gap: 45px; }
.block-widget { background: var(--light-card); padding: 35px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid var(--border-color); }
.block-title { font-size: 17px; font-weight: 900; text-transform: uppercase; margin-bottom: 28px; position: relative; padding-bottom: 14px; letter-spacing: 0.5px; color: var(--text-main); border-bottom: 2px solid var(--border-color); }
.block-title::after { content: ''; position: absolute; bottom: -2px; left: 0; width: 60px; height: 2px; background: var(--primary-gradient); }

/* Realtime Advanced Analytics Display Block Counters */
.analytics-box { display: grid; grid-template-columns: 1fr 1fr; gap: 18px; margin-top: 10px; }
.analytic-card { background: var(--light-bg); padding: 20px; border-radius: 14px; text-align: center; border: 1px solid var(--border-color); transition: var(--transition); }
.analytic-card:hover { border-color: var(--accent-color); transform: translateY(-3px); }
.analytic-num { font-size: 24px; font-weight: 900; color: var(--accent-color); margin-bottom: 5px; }
.analytic-label { font-size: 12.5px; font-weight: 700; color: var(--text-muted); text-transform: uppercase; }

/* Premium Advanced Email Newsletter Box Widget */
.newsletter-box { background: linear-gradient(135deg, #0f172a 0%, #1e293b 100%); color: #fff; padding: 35px; border-radius: var(--radius-mega); border: 1px solid rgba(255,255,255,0.05); }
.newsletter-box h3 { font-size: 20px; font-weight: 900; margin-bottom: 10px; color: #fff; }
.newsletter-box p { font-size: 14px; color: #94a3b8; line-height: 1.6; margin-bottom: 22px; }
.news-form-group { display: flex; flex-direction: column; gap: 12px; }
.news-input { padding: 15px 18px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: #fff; outline: none; font-weight: 600; }
.news-btn { background: var(--primary-gradient); color: #fff; border: none; padding: 15px; border-radius: 12px; font-weight: 900; cursor: pointer; box-shadow: var(--neon-glow); }

/* Native Widget Core Form Field Inputs Elements */
.search-input-group form { display: flex; gap: 12px; width: 100%; }
.search-field { flex-grow: 1; padding: 16px 22px; border: 1px solid var(--border-color); border-radius: 14px; background: var(--light-bg); color: var(--text-main); font-weight: 600; outline: none; transition: var(--transition); }
.search-field:focus { border-color: var(--accent-color); background: var(--light-card); box-shadow: 0 0 0 4px rgba(255,30,86,0.1); }
.search-go-btn { background: var(--primary-gradient); color: #fff; border: none; padding: 0 26px; border-radius: 14px; font-weight: 900; cursor: pointer; box-shadow: var(--neon-glow); }

.tag-cloud-list { display: flex; flex-wrap: wrap; gap: 12px; }
.tag-cloud-list li a { display: block; background: var(--light-bg); padding: 9px 20px; font-size: 14px; font-weight: 700; border-radius: 12px; border: 1px solid var(--border-color); }
.tag-cloud-list li a:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-4px); box-shadow: var(--neon-glow); }

.bio-avatar { width: 110px; height: 110px; border-radius: 50%; margin: 0 auto 20px; border: 4px solid var(--light-card); box-shadow: 0 0 0 3px var(--accent-color); object-fit: cover; display: block; }
.bio-title { font-size: 20px; font-weight: 800; margin-bottom: 12px; text-align: center; }
.bio-desc { font-size: 15px; color: var(--text-muted); line-height: 1.65; text-align: center; margin-bottom: 20px; }
.bio-more-link { display: block; text-align: center; font-size: 13.5px; font-weight: 800; color: var(--accent-color); text-transform: uppercase; letter-spacing: 0.5px; }

/* High-End Enterprise Tier Massive Footer Layout Architecture */
footer { background: #020617; color: #94a3b8; padding: 100px 0 50px; margin-top: 110px; border-top: 5px solid rgba(255, 30, 86, 0.35); }
.footer-grid-container { display: grid; grid-template-columns: repeat(auto-fit, minmax(290px, 1fr)); gap: 60px; margin-bottom: 60px; }
.footer-widget-box h3 { color: #fff; margin-bottom: 28px; font-size: 23px; font-weight: 900; position: relative; }
.footer-widget-box h3::after { content: ''; position: absolute; bottom: -8px; left: 0; width: 55px; height: 3px; background: var(--primary-gradient); }
.footer-widget-box p { font-size: 15.5px; line-height: 1.85; }
.footer-links-menu li { margin-bottom: 16px; font-size: 15.5px; font-weight: 700; }
.footer-links-menu li a:hover { color: #fff; padding-left: 10px; }

.footer-legal-base { border-top: 1px solid rgba(255,255,255,0.06); padding-top: 40px; text-align: center; font-size: 15.5px; font-weight: 700; color: #475569; }
.footer-legal-base a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 900; }

#back-to-top { position: fixed; bottom: 40px; right: 40px; background: var(--primary-gradient); color: #fff; width: 55px; height: 55px; border-radius: 18px; display: none; align-items: center; justify-content: center; cursor: pointer; z-index: 99999; box-shadow: var(--neon-glow); border: none; transition: var(--transition); font-size: 18px; }
#back-to-top:hover { transform: translateY(-6px) scale(1.05); }

body.script:
//
// 1. Premium Theme Dark/Light Modes System Core Toggle Engine
const toggleEngineBtn = document.getElementById('dark-mode-engine-btn');
const themeIconSymbol = toggleEngineBtn.querySelector('i');

toggleEngineBtn.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        themeIconSymbol.className = 'fas fa-sun';
    } else {
        themeIconSymbol.className = 'fas fa-moon';
    }
});

// 2. Linear Reading Progress Scroller Metric Monitor
window.addEventListener('scroll', () => {
    const currentScrollMetric = document.body.scrollTop || document.documentElement.scrollTop;
    const absoluteCalculatedHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const currentPercentageRatio = (currentScrollMetric / absoluteCalculatedHeight) * 100;
    document.getElementById('progress-bar').style.width = currentPercentageRatio + '%';

    const backToTopTrigger = document.getElementById('back-to-top');
    if(currentScrollMetric > 500) { backToTopTrigger.style.display = 'flex'; } else { backToTopTrigger.style.display = 'none'; }
});

document.getElementById('back-to-top').addEventListener('click', () => {
    window.scrollTo({top: 0, behavior: 'smooth'});
});

// 3. Automated Indian Standard Time Zone Clock Generator
document.getElementById('live-clock-system').innerText = new Date().toLocaleDateString('hi-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
//
